// And groups predicates with the AND operator between them.
func And(predicates ...predicate.OAuthDeviceAuthorisation) predicate.OAuthDeviceAuthorisation {
	return predicate.OAuthDeviceAuthorisation(sql.AndPredicates(predicates...))
}

// Or groups predicates with the OR operator between them.
func Or(predicates ...predicate.OAuthDeviceAuthorisation) predicate.OAuthDeviceAuthorisation {
	return predicate.OAuthDeviceAuthorisation(sql.OrPredicates(predicates...))
}

// Not applies the not operator on the given predicate.
func Not(p predicate.OAuthDeviceAuthorisation) predicate.OAuthDeviceAuthorisation {
	return predicate.OAuthDeviceAuthorisation(sql.NotPredicates(p))
}
